  val n = points.length
  if (n < 4) return 0L

  val lines = HashMap.empty[(Double, Double), HashSet[(Long, Long)]]

  for {
    i <- 0 until n
    j <- i + 1 until n
  } {
    val x1 = points(i)(0)
    val y1 = points(i)(1)
    val x2 = points(j)(0)
    val y2 = points(j)(1)
    val (slope, intercept) = 
      if (x1 == x2) {
        (Double.PositiveInfinity, x1.toDouble)
