        m1, b1 = k1
        m2, b2 = k2
        if m1 == m2:
            continue
        n1 = len(lines[k1])
        n2 = len(lines[k2])
        common = line_pairs[pair]
        total += (n1 - common) * (n2 - common)

    return total // 2
